mcp-tool-definition-pattern.pattern:
// Pattern structure:
// 1. Define tool object with IMCPTool interface
// 2. Use snake_case for tool name
// 3. Provide clear description with usage examples
// 4. Define strict inputSchema with JSON Schema
// 5. Implement handler with try-catch
// 6. Return structured MCPToolResponse
// 7. Handle errors gracefully with isError flag

export const toolName: IMCPTool = {
  name: 'tool_name',
  description: 'Description with examples',
  inputSchema: {
    type: 'object',
    properties: { /* ... */ },
    required: ['param1']
  },
  handler: async (args: unknown) => {
    try {
      // 1. Type cast and validate args
      // 2. Execute business logic
      // 3. Return success response
    } catch (error) {
      // Return error response
      return {
        content: [{ type: 'text', text: error.message }],
        isError: true
      };
    }
  }
};

examples:
export const readImageTool: IMCPTool = {
  name: 'read_image',
  description: 'Reads an image from file path or URL and returns image data',
  inputSchema: {
    type: 'object',
    properties: {
      source: {
        type: 'string',
        description: 'File path or URL of the image'
      },
      includeMetadata: {
        type: 'boolean',
        description: 'Whether to include EXIF metadata',
        default: false
      }
    },
    required: ['source']
  },
  handler: async (args: unknown) => {
    try {
      const { source, includeMetadata } = args as ReadImageArgs;
      const imageData = await imageReader.read(source);

      return {
        content: [{
          type: 'image',
          data: imageData.base64,
          mimeType: `image/${imageData.format}`
        }]
      };
    } catch (error) {
      return {
        content: [{
          type: 'text',
          text: `Error reading image: ${error.message}`
        }],
        isError: true
      };
    }
  }
};

custom-error-classes-pattern.pattern:
// Base pattern for domain errors:
export class DomainError extends Error {
  constructor(
    message: string,
    public readonly context?: Record<string, unknown>,
    public readonly cause?: Error
  ) {
    super(message);
    this.name = this.constructor.name;
    Error.captureStackTrace(this, this.constructor);
  }

  toJSON() {
    return {
      name: this.name,
      message: this.message,
      context: this.context,
      cause: this.cause?.message
    };
  }
}

// Specific errors:
export class ImageReadError extends DomainError {}
export class ImageFormatError extends DomainError {}
export class ImageProcessingError extends DomainError {}
export class MetadataExtractionError extends DomainError {}

examples:
export class ImageReadError extends Error {
  constructor(message: string, public readonly source: string, public readonly cause?: Error) {
    super(message);
    this.name = 'ImageReadError';
  }
}

export class ImageFormatError extends Error {
  constructor(public readonly format: string, public readonly supportedFormats: string[]) {
    super(`Unsupported image format: ${format}. Supported: ${supportedFormats.join(', ')}`);
    this.name = 'ImageFormatError';
  }
}

