examples:
export class ImageReaderFactory {
  private readers: Map<string, IImageReader>;

  constructor() {
    this.readers = new Map([
      ['file', new FileImageReader()],
      ['url', new URLImageReader()],
      ['buffer', new BufferImageReader()]
    ]);
  }

  getReader(source: string | Buffer): IImageReader {
    if (Buffer.isBuffer(source)) {
      return this.readers.get('buffer')!;
    }
    if (source.startsWith('http://') || source.startsWith('https://')) {
      return this.readers.get('url')!;
    }
    return this.readers.get('file')!;
  }
}

vs-code-extension-with-mcp-server.pattern:
// Extension structure:
// 1. extension.ts - Entry point with activate/deactivate
// 2. MCPServerManager - Manages server lifecycle
// 3. Commands registration for user interaction
// 4. Configuration provider for settings
// 5. Status bar integration for server status

// Key files:
// - extension.ts (activate, deactivate)
// - server-manager.ts (start, stop, restart server)
// - package.json (contributes: commands, configuration)
// - server/index.ts (MCP server implementation)

// Lifecycle:
// activate() -> Start server -> Register tools -> Ready
// deactivate() -> Stop server -> Cleanup resources

examples:
// extension.ts
export function activate(context: vscode.ExtensionContext) {
  const serverManager = new MCPServerManager(context);

  context.subscriptions.push(
    vscode.commands.registerCommand('mcp-image-reader.start', () => {
      serverManager.start();
    }),
    vscode.commands.registerCommand('mcp-image-reader.stop', () => {
      serverManager.stop();
    })
  );

  // Auto-start server
  serverManager.start();
}

export function deactivate() {
  // Cleanup
}
